import test from 'node:test';
import assert from 'node:assert/strict';
import { buildTlsOptions } from '../src/tls-options.mjs';

test('optional mode requests a certificate without rejecting an absent client identity', () => {
  assert.deepEqual(buildTlsOptions({
    cert: 'server-cert',
    key: 'server-key',
    clientAuth: 'optional',
  }), {
    cert: 'server-cert',
    key: 'server-key',
    requestCert: true,
    rejectUnauthorized: false,
  });
});
